__kernel void bpnn_layerforward_ocl(__global float *input, __global float *output, 
                                    __global float *weights, __global float *partial_sum,
                                    __local float *local_mem1, __local float *local_mem2,
                                    int n1, int n2) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= n2 && k <= n1) {
        float weight_val = weights[k * (n2 + 1) + j];
        float input_val = input[k];

        local_mem1[k] = input_val;
        local_mem2[k * WIDTH + j] = weight_val * input_val;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (j >= 1 && j <= n2 && k == 0) {
        float sum = 0.0f;
        for (int i = 0; i <= n1; i++) {
            sum += local_mem2[i * WIDTH + j];
        }
        partial_sum[(j - 1)] = sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(__global float *delta, int ndelta,
                                      __global float *ly, int nly,
                                      __global float *w, __global float *oldw) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k <= nly) {
        float delta_val = delta[j];
        float ly_val = (k == 0) ? 1.0f : ly[k];
        float oldw_val = oldw[k * (ndelta + 1) + j];

        float new_dw = (0.3f * delta_val * ly_val) + (0.3f * oldw_val);
        w[k * (ndelta + 1) + j] += new_dw;
        oldw[k * (ndelta + 1) + j] = new_dw;
    }
}

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}
